        if (solid == null) continue;
        foreach (Face face in solid.Faces)
        {
            XYZ n = face.ComputeNormal(new UV(0.5, 0.5));
            if (n.IsAlmostEqualTo(rp.Normal) || n.IsAlmostEqualTo(-rp.Normal))
            { edgeRef = face.Reference; break; }
