        new XYZ(0.196850, 0, 0),
        new XYZ(0.196850, 0, 8.202100));

    Dimension dim = familyDoc.FamilyCreate.NewLinearDimension(
        elevView, dimLine, refs);

    if (dim != null && dim.IsReferencesValidForLabel())
        dim.FamilyLabel = pHeight;

    tx.Commit();
