        activeView,
        Line.CreateBound(new XYZ(-0.984252, 0.196850, 0), new XYZ(0.984252, 0.196850, 0)),
        refs);
    if (rDim != null)
    {
        rDim.AreSegmentsEqual = true;
        if (rDim.IsReferencesValidForLabel())
