            $"Smoke compartment area {area:F0} sq ft exceeds 22,500 sq ft maximum. "
            + "Ref: NFPA 101 S19.2.5.");
    }

    if (pLength != null)
    {
        double dim = pLength.AsDouble();
        if (dim > maxDimFt)
        {
            TaskDialog.Show("NFPA 101 S19.2.5 Violation",
