    double area      = pArea != null ? pArea.AsDouble() : 0;
    double storageHt = pStorageHt != null ? pStorageHt.AsDouble() : 0;
    bool hasSpr      = pHasSpr != null && pHasSpr.AsInteger() == 1;

    bool required = area > 12000 || (storageHt > 12.0);
    if (required && !hasSpr)
