// Check: floor-to-floor height >= structural depth + MEP plenum + finished ceiling + finished floor
// Typical breakdown: 4 in slab + beam depth + 18 in MEP plenum + 2 in ceiling + 1 in flooring
void ValidateFloorToFloorClearance(FamilyInstance floorInst)
{
    double minClearFt  = 7.000000; // 84 in net occupiable clear height -- IBC 1208.2

    Parameter pF2F     = floorInst.LookupParameter("Floor to Floor Height");
    Parameter pBeamD   = floorInst.LookupParameter("Structural Depth");
    Parameter pMEP     = floorInst.LookupParameter("MEP Plenum Depth");
    Parameter pCeiling = floorInst.LookupParameter("Ceiling Depth");
    Parameter pSlab    = floorInst.LookupParameter("Slab Thickness");
    if (pF2F == null) return;

    double f2f         = pF2F.AsDouble();
    double beamD       = pBeamD    != null ? pBeamD.AsDouble()    : 1.500000;  // 18 in default
    double mepPlenum   = pMEP      != null ? pMEP.AsDouble()      : 1.500000;  // 18 in default
    double ceilingD    = pCeiling  != null ? pCeiling.AsDouble()  : 0.166667;  // 2 in default
    double slab        = pSlab     != null ? pSlab.AsDouble()     : 0.333333;  // 4 in default
    double occupiable  = f2f - beamD - mepPlenum - ceilingD - slab;

    if (occupiable < minClearFt)
    {
        TaskDialog.Show("IBC 1208.2 Structural Clearance Warning",
            $"Occupiable clear height {occupiable * 12.0:F2} in is below required 84 in. "
            + $"Floor-to-floor: {f2f * 12.0:F1} in, Structural: {beamD * 12.0:F1} in, "
            + $"MEP: {mepPlenum * 12.0:F1} in, Ceiling: {ceilingD * 12.0:F1} in, Slab: {slab * 12.0:F1} in. "
            + "Ref: IBC 1208.2.");
    }
}

using Autodesk.Revit.DB;

// Face-based families use a generic model face-based template.
// The hosting face defines the work plane; geometry projects from it.
// Key: set the family's hosting requirement to wall face.

// This code runs at family document load / setup time (no Transaction needed
// for document property changes in the family editor).
FamilyManager famMgr = familyDoc.FamilyManager;

// Confirm the template supports face-based hosting
// (check via familyDoc.FamilyPlacementType)
FamilyPlacementType placementType = familyDoc.FamilyPlacementType;
// Expected: FamilyPlacementType.OneLevelBasedHosted or WorkPlaneBased

// Add a standard Depth parameter to control projection from wall face
using (Transaction tx = new Transaction(familyDoc, "Setup Face-Based Parameters"))
{
    tx.Start();

    // Reference plane parallel to the hosting face (at projection depth)
