    double h = 8.858268; // height = 2700 mm

    // Profile in the XZ plane: rectangle from (0,0,0) to (r,0,h)
    CurveArray loop = new CurveArray();
    loop.Append(Line.CreateBound(new XYZ(0, 0, 0), new XYZ(r, 0, 0)));
