famMgr.Set(pT,   0.016404);   // 5 mm
famMgr.Set(pL,   9.842520); // 3000 mm default

using (Transaction tx = new Transaction(familyDoc, "Create Equal Angle"))
{
    tx.Start();

    double a = 0.164042; // leg length 50 mm
    double t = 0.016404;   // thickness 5 mm
    double L = 9.842520; // 3000 mm length

    // L-shape profile in YZ plane, corner at origin
    // Horizontal leg along +Y, vertical leg along +Z
