famMgr.Set(pHw, 1.476378); // 450 mm
famMgr.Set(pBf, 2.296588); // 700 mm
famMgr.Set(pHf, 0.393701); // 120 mm
famMgr.Set(pL,  16.404199);  // 5000 mm

using (Transaction tx = new Transaction(familyDoc, "Create T-Beam"))
{
    tx.Start();

    double bw = 0.820210; // web width 250 mm
    double hw = 1.476378; // web depth 450 mm
    double bf = 2.296588; // flange width 700 mm
    double hf = 0.393701; // flange thickness 120 mm
    double L  = 16.404199;  // span 5000 mm

    // T-section profile: flange at top (z=0), web hanging down
    double totalH = hw + hf;
    CurveArray loop = new CurveArray();
