    double bw = 2.624672; double bd = 1.640420; double bh = 2.952756;

    CurveArrArray profile = new CurveArrArray();
    CurveArray loop = new CurveArray();
    loop.Append(Line.CreateBound(new XYZ(-bw/2, -bd/2, 0), new XYZ( bw/2, -bd/2, 0)));
    loop.Append(Line.CreateBound(new XYZ( bw/2, -bd/2, 0), new XYZ( bw/2,  bd/2, 0)));
    loop.Append(Line.CreateBound(new XYZ( bw/2,  bd/2, 0), new XYZ(-bw/2,  bd/2, 0)));
