// The `end` argument of NewExtrusion(isSolid, profile, sketchPlane, end) is a one-time LITERAL.
// The extrusion's flexing comes from aligning its top/bottom FACES to labeled ref planes,
// not from re-passing end. Same pattern as Width: make a ref plane, align the face, label a
// dimension that separates the origin from the ref plane, bind the param to the dimension.

using (Transaction tx = new Transaction(familyDoc, "Parametric Depth Extrusion"))
{
    tx.Start();

    FamilyManager fm = familyDoc.FamilyManager;
    FamilyParameter pDepth = fm.AddParameter("Depth", GroupTypeId.Geometry, SpecTypeId.Length, false);
    fm.Set(pDepth, 1.0);

    // Create a ref plane at Z = 1.0 (the initial top of the extrusion)
    ReferencePlane rpTop = familyDoc.FamilyCreate.NewReferencePlane(
        new XYZ(1, 0, 1.0),   // bubble end, at desired Z
        new XYZ(0, 0, 1.0),   // free end
        XYZ.BasisY,            // cut vector (perpendicular to plane normal)
        familyDoc.ActiveView);
    rpTop.Name = "Top";

    // Built-in origin ref plane (the sketch plane at Z=0)
    ReferencePlane rpBottom = new FilteredElementCollector(familyDoc)
        .OfClass(typeof(ReferencePlane)).Cast<ReferencePlane>()
        .First(r => r.Name == "Reference Level" || r.Name == "Center (Front/Back)");

    // Create the extrusion (end literal matches the ref plane's initial Z)
    SketchPlane sp = SketchPlane.Create(familyDoc, Plane.CreateByNormalAndOrigin(XYZ.BasisZ, XYZ.Zero));
    CurveArrArray profile = new CurveArrArray();
    CurveArray loop = new CurveArray();
    loop.Append(Line.CreateBound(new XYZ(-0.5, -0.5, 0), new XYZ( 0.5, -0.5, 0)));
    loop.Append(Line.CreateBound(new XYZ( 0.5, -0.5, 0), new XYZ( 0.5,  0.5, 0)));
    loop.Append(Line.CreateBound(new XYZ( 0.5,  0.5, 0), new XYZ(-0.5,  0.5, 0)));
    loop.Append(Line.CreateBound(new XYZ(-0.5,  0.5, 0), new XYZ(-0.5, -0.5, 0)));
    profile.Append(loop);
    Extrusion ext = familyDoc.FamilyCreate.NewExtrusion(true, profile, sp, 1.0);

    // Find the top (+Z) face reference
    Options opts = new Options { ComputeReferences = true, View = familyDoc.ActiveView };
    Reference topRef = null;
    foreach (GeometryObject go in ext.get_Geometry(opts))
        if (go is Solid solid)
            foreach (Face f in solid.Faces)
                if (f is PlanarFace pf && pf.FaceNormal.IsAlmostEqualTo(XYZ.BasisZ))
                    topRef = pf.Reference;

    // Align the top face to the Top ref plane
    familyDoc.FamilyCreate.NewAlignment(familyDoc.ActiveView, rpTop.GetReference(), topRef);

    // Dimension from bottom plane to top plane, label with Depth
    ReferenceArray refs = new ReferenceArray();
    refs.Append(rpBottom.GetReference());
    refs.Append(rpTop.GetReference());
    Dimension dim = familyDoc.FamilyCreate.NewLinearDimension(
        familyDoc.ActiveView,
        Line.CreateBound(new XYZ(2, 0, 0), new XYZ(2, 0, 1.0)),
        refs);
    dim.FamilyLabel = pDepth;

    tx.Commit();
}

using Autodesk.Revit.DB;

static bool TestFlex(Document familyDoc, string paramName, double newValue)
{
    FamilyManager fm = familyDoc.FamilyManager;
    FamilyParameter param = fm.get_Parameter(paramName);
    if (param == null)
        throw new InvalidOperationException($"Parameter {paramName} not found");
    if (param.IsReporting)
        throw new InvalidOperationException($"{paramName} is a reporting parameter -- cannot Set");

    // Capture geometry bounding box before
    FamilyType currentType = fm.CurrentType;
    if (currentType == null)
    {
        // Family has no types defined -- create a default one
        using (Transaction t = new Transaction(familyDoc, "Add default type")) {
            t.Start();
            fm.NewType("Default");
            t.Commit();
        }
        currentType = fm.CurrentType;
    }

    // Set the new value and regenerate
    using (Transaction t = new Transaction(familyDoc, $"Flex {paramName}"))
    {
        t.Start();
        fm.Set(param, newValue);
        familyDoc.Regenerate();   // force geometry recomputation
        t.Commit();
    }

    // Check: if the regenerate fails silently (constraints over-constrained),
    // Revit reports warnings rather than throwing. Query the document warnings.
    var warnings = familyDoc.GetWarnings();
    foreach (var w in warnings)
    {
        string desc = w.GetDescriptionText();
        if (desc.Contains("Constraints are not satisfied") || desc.Contains("overconstrained"))
            return false;   // Flex failed -- geometry couldn't adjust
    }

    return true;
}

